# ═══ DRAKEN DIGEST DEPLOY — Q2 2026 ═══
# Deploys the full Dragon Digest (original samizdat version + 6 inline figures)
# Patches build.js, updates system.json, runs build, verifies output.
# Run from anywhere. Repo assumed at C:\Draken\draken.info\

$repo     = "C:\Draken\draken.info"
$digestDir = "$repo\digest\q2-2026"
$sysJson   = "$repo\static\data\system.json"
$buildJs   = "$repo\build.js"

# Source file (the original you downloaded)
$sourceFile = "C:\Users\Bubben\Downloads\The Dragon Digest — Q2 2026.html"

Write-Host "═══ Draken Digest Deploy ═══" -ForegroundColor Green

# ── Step 1: Write digest index.html ──
Write-Host "1. Writing digest HTML..." -ForegroundColor Cyan
New-Item -ItemType Directory -Force -Path $digestDir | Out-Null

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$digestDir\index.html", $bytes)
$sz = (Get-Item "$digestDir\index.html").Length
Write-Host "   Written: $sz bytes" -ForegroundColor Green

# ── Step 2: Patch build.js ──
Write-Host "2. Patching build.js..." -ForegroundColor Cyan
$bjs = Get-Content $buildJs -Raw
if ($bjs -notmatch 'buildDigestPages') {
    $fn = @'

// ── DIGEST pages ──
function buildDigestPages() {
  const src = path.join(__dirname, 'digest');
  const dst = path.join(DIST_DIR, 'digest');
  if (!fs.existsSync(src)) return;
  copyDirSync(src, dst);
  let n = 0;
  for (const e of fs.readdirSync(src, { withFileTypes: true }))
    if (e.isDirectory() && fs.existsSync(path.join(src, e.name, 'index.html'))) n++;
  console.log(`  \u2713 digest/ (${n} issue${n!==1?'s':''})`);
}
'@
    $anchor = "buildSlaskPage(baseTpl);"
    $bjs = $bjs -replace [regex]::Escape($anchor), ($anchor + "`n  buildDigestPages();")
    $bjs = $bjs + $fn
    # Add sitemap entry
    $sitemapAnchor = "`<url><loc>`${b}/sheaf-game/</loc><priority>0.7</priority></url>`\`n`""
    $sitemapNew    = "`<url><loc>`${b}/sheaf-game/</loc><priority>0.7</priority></url>`\`n`" +`n    `"`<url><loc>`${b}/digest/q2-2026/</loc><priority>0.8</priority></url>`\`n`" +"
    $bjs = $bjs -replace [regex]::Escape($sitemapAnchor), $sitemapNew
    Set-Content $buildJs -Value $bjs -Encoding UTF8 -NoNewline
    Write-Host "   build.js patched" -ForegroundColor Green
} else {
    Write-Host "   build.js already patched — skipping" -ForegroundColor Yellow
}

